// Extraire le body du webhook (n8n le met dans .body ou à la racine)
const raw = $input.first().json
const body = (raw.body && typeof raw.body === 'object') ? raw.body : raw

const case_id = body.case_id || null
const doc_id = body.doc_id || null
const storage_path = body.storage_path || ''
const pdf_url = body.pdf_url || null

// Construire l'URL de téléchargement
// Priorité 1 : signed URL générée par l'app
// Priorité 2 : URL directe Supabase Storage avec auth service role
const supabaseBase = ($vars.SUPABASE_URL || 'https://ctfqgvrzstwtkborbhai.supabase.co').replace(/\/+$/, '')
const downloadUrl = (pdf_url && pdf_url.startsWith('http'))
  ? pdf_url
  : supabaseBase + '/storage/v1/object/documents/' + storage_path

console.log('downloadUrl:', downloadUrl)
console.log('case_id:', case_id, 'doc_id:', doc_id)

return [{ json: { downloadUrl, case_id, doc_id, storage_path } }]

// IDs depuis le nœud Préparer URL
const prep = $('Préparer URL').first().json
const case_id = prep.case_id
const doc_id = prep.doc_id

// Réponse Groq
const raw = $input.first().json?.choices?.[0]?.message?.content || ''

let summary = null
let extracted_date = null
let doc_type = null

try {
  const cleaned = raw
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```\s*$/i, '')
    .trim()
  const o = JSON.parse(cleaned)
  summary = typeof o.summary === 'string' ? o.summary : null
  if (o.extracted_date && /^\d{4}-\d{2}-\d{2}$/.test(String(o.extracted_date))) {
    extracted_date = o.extracted_date
  }
  doc_type = typeof o.doc_type === 'string' ? o.doc_type : null
} catch (e) {
  summary = raw.slice(0, 500) || 'Extraction automatique'
}

console.log('Extraction OK — case_id:', case_id, 'summary:', summary, 'date:', extracted_date)

return [{ json: { case_id, doc_id, summary, extracted_date, doc_type } }]
